//! Video concat/normalization wrapper.
//!
//! This keeps demo assembly on the sovereign frffmpeg surface instead of letting
//! each script invent its own ffmpeg command. Inputs are scaled/padded to a
//! common canvas and concatenated into one H.264 MP4 without audio.

use std::io;
use std::process::Command;

pub fn concat_videos(out_path: &str, input_paths: &[String]) -> io::Result<()> {
    if input_paths.is_empty() {
        return Err(io::Error::new(
            io::ErrorKind::InvalidInput,
            "frffmpeg concat needs at least one input video",
        ));
    }

    let mut args: Vec<String> = vec!["-v".into(), "error".into()];
    for input in input_paths {
        args.push("-i".into());
        args.push(input.clone());
    }

    let mut filter_parts: Vec<String> = Vec::with_capacity(input_paths.len() + 1);
    for index in 0..input_paths.len() {
        filter_parts.push(format!(
            "[{index}:v]scale=1920:1080:force_original_aspect_ratio=decrease,\
pad=1920:1080:(ow-iw)/2:(oh-ih)/2,setsar=1,fps=30[v{index}]"
        ));
    }
    let labels = (0..input_paths.len())
        .map(|index| format!("[v{index}]"))
        .collect::<Vec<_>>()
        .join("");
    filter_parts.push(format!("{labels}concat=n={}:v=1:a=0[outv]", input_paths.len()));

    args.extend([
        "-filter_complex".into(),
        filter_parts.join(";"),
        "-map".into(),
        "[outv]".into(),
        "-c:v".into(),
        "libx264".into(),
        "-preset".into(),
        "veryfast".into(),
        "-crf".into(),
        "20".into(),
        "-pix_fmt".into(),
        "yuv420p".into(),
        "-movflags".into(),
        "+faststart".into(),
        "-y".into(),
        out_path.into(),
    ]);

    let output = Command::new("ffmpeg").args(&args).output()?;
    if !output.status.success() {
        return Err(io::Error::other(format!(
            "ffmpeg concat failed ({}): {}",
            output.status,
            String::from_utf8_lossy(&output.stderr).trim()
        )));
    }
    Ok(())
}
